/** Find Annexe C assignment for a set of advancing third-place groups. */
export function findAnnexeC(advancingGroups: string[]): Record<string, string> | null {
  const key = [...advancingGroups].sort().join('');
  return ANNEXE_C[key] ?? null;
}
