/** Returns the Annexe C option number for a set of advancing third-place groups, or null if not found. */
export function findAnnexeCOption(advancingGroups: string[]): number | null {
  const key = [...advancingGroups].sort().join('')
  return ANNEXE_C_OPTIONS[key] ?? null
}
